/**
 * PressVideo — Standalone Music Player.
 * YouTube Music-inspired full-screen player with persistent mini-bar.
 * Vanilla JS. No jQuery, no Bootstrap.
 *
 * Exposes: window.pvMusicPlayer = { openFromTrigger, isActive, minimize, restore, close }
 */
(function () {
    'use strict';

    var PLAYER_ID = 'pv-music-player';

    // DOM refs
    var player, panel, backdrop,
        minimizeBtn, closeBtn,
        artWrap, spinner, iframeHolder,
        titleEl,
        progressBar, progressFill, timeCur, timeDur,
        prevBtn, playBtn, nextBtn, shuffleBtn, loopBtn, loopBadge,
        muteBtn, volumeTrack, volumeFill,
        queueList, queueCountEl,
        miniBar, miniThumb, miniTitle,
        miniProgressFill, miniProgressBar,
        miniPrevBtn, miniPlayBtn, miniNextBtn,
        miniExpandBtn, miniCloseBtn,
        stageEl, prevTile, nextTile, posterEl, artWrap;

    // State
    var playlist         = [];
    var current          = 0;
    var minimized        = false;
    var active           = false;
    var loopMode         = 'none'; // 'none' | 'all' | 'one'
    var shuffleActive    = false;
    var originalPlaylist = [];
    var currentVolume    = 80;
    var isMuted          = false;
    var isDraggingVol    = false;

    // YT Player
    var ytPlayer         = null;
    var ytApiReady       = !!(window.YT && window.YT.Player);
    var ytApiQueue       = [];
    var progressInterval = null;
    var spinnerTimer     = null;

    /* ── Bootstrap YT IFrame API ─────────────────────────────────── */
    (function loadYt() {
        if (ytApiReady) return;
        var prev = window.onYouTubeIframeAPIReady;
        window.onYouTubeIframeAPIReady = function () {
            if (typeof prev === 'function') prev();
            ytApiReady = true;
            ytApiQueue.forEach(function (fn) { fn(); });
            ytApiQueue = [];
        };
        if (!document.getElementById('pv-yt-api')) {
            var s = document.createElement('script');
            s.id  = 'pv-yt-api';
            s.src = 'https://www.youtube.com/iframe_api';
            document.head.appendChild(s);
        }
    }());

    function whenYtReady(fn) { ytApiReady ? fn() : ytApiQueue.push(fn); }

    /* ── Init ─────────────────────────────────────────────────────── */
    function init() {
        player = document.getElementById(PLAYER_ID);
        if (!player) return;

        if (window.pvMusicSettings && window.pvMusicSettings.eqBars) {
            player.classList.add('pvm-player--eq');
        }

        panel          = player.querySelector('.pvm-panel');
        backdrop       = player.querySelector('.pvm-backdrop');
        minimizeBtn    = player.querySelector('.pvm-minimize');
        closeBtn       = player.querySelector('.pvm-close-btn');
        artWrap        = player.querySelector('.pvm-art-wrap');
        spinner        = player.querySelector('.pvm-spinner');
        iframeHolder   = player.querySelector('.pvm-iframe-holder');
        titleEl        = player.querySelector('.pvm-title');
        progressBar    = player.querySelector('.pvm-progress-bar');
        progressFill   = player.querySelector('.pvm-progress-fill');
        timeCur        = player.querySelector('.pvm-time-cur');
        timeDur        = player.querySelector('.pvm-time-dur');
        prevBtn        = player.querySelector('.pvm-prev-btn');
        playBtn        = player.querySelector('.pvm-play-btn');
        nextBtn        = player.querySelector('.pvm-next-btn');
        shuffleBtn     = player.querySelector('.pvm-shuffle-btn');
        loopBtn        = player.querySelector('.pvm-loop-btn');
        loopBadge      = player.querySelector('.pvm-loop-badge');
        muteBtn        = player.querySelector('.pvm-mute-btn');
        volumeTrack    = player.querySelector('.pvm-volume-track');
        volumeFill     = player.querySelector('.pvm-volume-fill');
        queueList      = player.querySelector('.pvm-queue-list');
        queueCountEl   = player.querySelector('.pvm-queue-count');
        stageEl        = player.querySelector('.pvm-stage');
        prevTile       = player.querySelector('.pvm-tile--prev');
        nextTile       = player.querySelector('.pvm-tile--next');
        posterEl       = player.querySelector('.pvm-art-poster');
        artWrap        = player.querySelector('.pvm-tile--current .pvm-art-wrap');
        miniBar        = player.querySelector('.pvm-mini-bar');
        miniThumb      = player.querySelector('.pvm-mini-thumb');
        miniTitle      = player.querySelector('.pvm-mini-title');
        miniProgressFill = player.querySelector('.pvm-mini-progress-fill');
        miniProgressBar  = player.querySelector('.pvm-mini-progress');
        miniPrevBtn    = player.querySelector('.pvm-mini-prev');
        miniPlayBtn    = player.querySelector('.pvm-mini-play');
        miniNextBtn    = player.querySelector('.pvm-mini-next');
        miniExpandBtn  = player.querySelector('.pvm-mini-expand');
        miniCloseBtn   = player.querySelector('.pvm-mini-close');

        if (minimizeBtn) minimizeBtn.addEventListener('click', minimize);
        if (closeBtn)    closeBtn.addEventListener('click', forceClose);
        if (backdrop)    backdrop.addEventListener('click', minimize);

        if (prevBtn)    prevBtn.addEventListener('click', function () { navigate(-1); });
        if (nextBtn)    nextBtn.addEventListener('click', function () { navigate(1); });
        if (prevTile)   prevTile.addEventListener('click', function () { navigate(-1); });
        if (nextTile)   nextTile.addEventListener('click', function () { navigate(1); });
        if (playBtn)    playBtn.addEventListener('click', togglePlay);
        if (loopBtn)    loopBtn.addEventListener('click', cycleLoop);
        if (shuffleBtn) shuffleBtn.addEventListener('click', toggleShuffle);

        if (progressBar) {
            progressBar.addEventListener('click', function (e) {
                var rect = progressBar.getBoundingClientRect();
                seekToPct(Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width)));
            });
        }

        // Volume controls
        if (muteBtn) muteBtn.addEventListener('click', toggleMute);
        if (volumeTrack) {
            volumeTrack.addEventListener('click', function (e) {
                if (isDraggingVol) return;
                var rect = volumeTrack.getBoundingClientRect();
                setVolume(Math.round(Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width)) * 100));
            });
            volumeTrack.addEventListener('mousedown', function (e) {
                isDraggingVol = true;
                onVolumeDrag(e);
            });
            volumeTrack.addEventListener('touchstart', function (e) {
                isDraggingVol = true;
                onVolumeDrag(e.touches[0]);
            }, { passive: true });
        }
        document.addEventListener('mousemove', function (e) { if (isDraggingVol) onVolumeDrag(e); });
        document.addEventListener('touchmove', function (e) { if (isDraggingVol) onVolumeDrag(e.touches[0]); }, { passive: true });
        document.addEventListener('mouseup',  function () { isDraggingVol = false; });
        document.addEventListener('touchend', function () { isDraggingVol = false; });

        if (miniPrevBtn)   miniPrevBtn.addEventListener('click', function () { navigate(-1); });
        if (miniNextBtn)   miniNextBtn.addEventListener('click', function () { navigate(1); });
        if (miniPlayBtn)   miniPlayBtn.addEventListener('click', togglePlay);
        if (miniExpandBtn) miniExpandBtn.addEventListener('click', restore);
        if (miniCloseBtn)  miniCloseBtn.addEventListener('click', forceClose);

        if (miniProgressBar) {
            miniProgressBar.addEventListener('click', function (e) {
                var rect = miniProgressBar.getBoundingClientRect();
                seekToPct(Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width)));
            });
        }

        document.addEventListener('keydown', function (e) {
            if (!active) return;
            // Space only when player is not minimized and focus isn't in an input
            if (e.code === 'Space' && document.activeElement.tagName !== 'INPUT' &&
                document.activeElement.tagName !== 'TEXTAREA' && document.activeElement.tagName !== 'BUTTON') {
                e.preventDefault();
                togglePlay();
            }
            if (minimized) return;
            if (e.key === 'Escape')     { e.preventDefault(); minimize(); }
            if (e.key === 'ArrowRight') { e.preventDefault(); navigate(1); }
            if (e.key === 'ArrowLeft')  { e.preventDefault(); navigate(-1); }
            if (e.key === 'ArrowUp')    { e.preventDefault(); setVolume(Math.min(100, currentVolume + 5)); }
            if (e.key === 'ArrowDown')  { e.preventDefault(); setVolume(Math.max(0, currentVolume - 5)); }
            if (e.key === 'm' || e.key === 'M') { e.preventDefault(); toggleMute(); }
        });

        updateVolumeUI(); // set initial volume icon state
    }

    /* ── Public API ───────────────────────────────────────────────── */
    function openFromTrigger(trigger, plData, anchorId) {
        var fallback = {
            youtubeId: anchorId || trigger.dataset.youtubeId || '',
            embedUrl:  trigger.dataset.embedUrl  || '',
            title:     trigger.dataset.title     || '',
            desc:      trigger.dataset.description || '',
            accent:    trigger.dataset.accent    || '#4f46e5',
            thumb:     trigger.dataset.thumb     || '',
            duration:  '',
            permalink: trigger.dataset.permalink || '',
            isMusic:   true,
            artist:    trigger.dataset.artist    || '',
            album:     trigger.dataset.album     || ''
        };

        if (plData && plData.length > 0) {
            var musicOnly = plData.filter(function (s) { return s.isMusic; });
            playlist = musicOnly.length > 0 ? musicOnly : [fallback];
            current  = playlist.findIndex(function (v) { return v.youtubeId === fallback.youtubeId; });
            if (current < 0) current = 0;
        } else {
            playlist = [fallback];
            current  = 0;
        }
        originalPlaylist = playlist.slice();

        active = true;
        openPanel();
    }

    function isActive() { return active; }

    /* ── Open / minimize / restore / close ───────────────────────── */
    function openPanel() {
        minimized = false;
        player.classList.add('pvm-open');
        player.classList.remove('pvm-minimized');
        player.setAttribute('aria-hidden', 'false');
        document.body.style.overflow = 'hidden';
        loadSlide(current);
        buildQueue();
        showEntryNotification();
    }

    function minimize() {
        if (!active) return;
        minimized = true;
        player.classList.remove('pvm-open');
        player.classList.add('pvm-minimized');
        document.body.style.overflow = '';
        updateMiniBar();
    }

    function restore() {
        if (!active || !minimized) return;
        minimized = false;
        player.classList.add('pvm-open');
        player.classList.remove('pvm-minimized');
        document.body.style.overflow = 'hidden';
    }

    function forceClose() {
        active    = false;
        minimized = false;
        player.classList.remove('pvm-open');
        player.classList.remove('pvm-minimized');
        player.setAttribute('aria-hidden', 'true');
        document.body.style.overflow = '';
        destroyPlayer();
    }

    /* ── Load slide ───────────────────────────────────────────────── */
    function loadSlide(index) {
        var slide = playlist[index];
        if (!slide) return;
        player.style.setProperty('--pv-accent', slide.accent || '#4f46e5');
        if (titleEl)    titleEl.textContent    = slide.title  || '';
        if (timeCur)          timeCur.textContent = '0:00';
        if (timeDur)          timeDur.textContent = '0:00';
        if (progressFill)     progressFill.style.width = '0%';
        if (miniProgressFill) miniProgressFill.style.width = '0%';

        // Show the poster (covers black flash during iframe destroy/recreate).
        // Prefer maxresdefault for a sharp poster; fall back to hqdefault, then
        // to the stored thumb if both fail (videos without high-res posters).
        if (posterEl) {
            setHiResThumb(posterEl, slide);
            posterEl.alt = slide.title || '';
        }
        if (artWrap) artWrap.classList.remove('pvm-art-wrap--ready');

        createYtPlayer(slide);
        updateNavBtns();
        updateMiniBar();
        updateCarousel();
    }

    /* ── Carousel side tiles (desktop coverflow) ─────────────────── */
    function updateCarousel() {
        if (!prevTile && !nextTile) return;
        var prevSlide = playlist[current - 1] || (loopMode === 'all' ? playlist[playlist.length - 1] : null);
        var nextSlide = playlist[current + 1] || (loopMode === 'all' ? playlist[0] : null);
        applyTile(prevTile, prevSlide);
        applyTile(nextTile, nextSlide);
    }

    function applyTile(tile, slide) {
        if (!tile) return;
        if (!slide) { tile.hidden = true; return; }
        tile.hidden = false;
        var img   = tile.querySelector('.pvm-tile__thumb');
        var label = tile.querySelector('.pvm-tile__label');
        if (img) {
            setHiResThumb(img, slide);
            img.alt = slide.title || '';
        }
        if (label) label.textContent = slide.title || '';
    }

    // Try maxresdefault.jpg first (1280×720). Many videos have it; if YouTube
    // didn't generate one, the load fails and we fall back to hqdefault, then
    // to whatever was stored in slide.thumb.
    function setHiResThumb(imgEl, slide) {
        var ytId = slide && slide.youtubeId;
        if (!ytId) {
            imgEl.removeAttribute('data-fallback-step');
            imgEl.src = (slide && slide.thumb) || '';
            return;
        }
        imgEl.dataset.fallbackStep = 'maxres';
        imgEl.onerror = function () {
            var step = imgEl.dataset.fallbackStep;
            if (step === 'maxres') {
                imgEl.dataset.fallbackStep = 'hq';
                imgEl.src = 'https://i.ytimg.com/vi/' + ytId + '/hqdefault.jpg';
            } else if (step === 'hq' && slide.thumb && slide.thumb !== imgEl.src) {
                imgEl.dataset.fallbackStep = 'stored';
                imgEl.src = slide.thumb;
            } else {
                imgEl.onerror = null;
            }
        };
        imgEl.src = 'https://i.ytimg.com/vi/' + ytId + '/maxresdefault.jpg';
    }

    // Real coverflow slide: snap tiles to "previous-state" positions instantly
    // (transitions disabled), then on the next frame remove the from-* class
    // so they transition smoothly to their new default positions. The center
    // tile's poster image covers the iframe destroy/recreate gap.
    function slideStage(direction) {
        if (!stageEl) return;
        var fromCls = direction > 0 ? 'pvm-stage--from-next' : 'pvm-stage--from-prev';
        stageEl.classList.add('pvm-stage--no-anim', fromCls);
        // Force reflow so the "from" state is committed without animation.
        void stageEl.offsetWidth;
        // Re-enable transitions, then remove the from-class on next frame so
        // tiles animate from the snapped "from" state to default.
        requestAnimationFrame(function () {
            stageEl.classList.remove('pvm-stage--no-anim');
            requestAnimationFrame(function () {
                stageEl.classList.remove(fromCls);
            });
        });
    }

    /* ── YT Player ────────────────────────────────────────────────── */
    function createYtPlayer(slide) {
        if (!iframeHolder) return;
        destroyPlayer();
        showSpinner();

        var ytId = slide.youtubeId;
        if (!ytId) { hideSpinner(); return; }

        var playFired = false;

        var div    = document.createElement('div');
        div.id     = 'pvm-yt-player';
        div.style.cssText = 'width:100%;height:100%';
        iframeHolder.innerHTML = '';
        iframeHolder.appendChild(div);

        spinnerTimer = setTimeout(hideSpinner, 3000);

        whenYtReady(function () {
            var el = document.getElementById('pvm-yt-player');
            if (!el || !el.isConnected) return;
            try {
                ytPlayer = new YT.Player('pvm-yt-player', {
                    videoId:    ytId,
                    width:      '100%',
                    height:     '100%',
                    playerVars: { autoplay: 1, rel: 0, modestbranding: 1, playsinline: 1 },
                    events: {
                        onReady: function () {
                            clearTimeout(spinnerTimer);
                            hideSpinner();
                            var iframe = iframeHolder.querySelector('iframe');
                            if (iframe) iframe.style.cssText = 'width:100%;height:100%;border:none;display:block;position:relative;z-index:1';
                            // Music mode is audio-focused — keep the poster image
                            // visible over the iframe instead of fading to the
                            // letterboxed video. Audio plays from behind.
                            // Apply persisted volume
                            try {
                                if (isMuted) ytPlayer.mute();
                                else { ytPlayer.unMute(); ytPlayer.setVolume(currentVolume); }
                            } catch (e) {}
                            startTracking(ytId);
                            // Fire play if autoplay already kicked in before onReady
                            try {
                                if (!playFired && ytPlayer.getPlayerState() === 1) {
                                    playFired = true;
                                    pvTrackEvent('play', ytId);
                                }
                            } catch (e) {}
                        },
                        onStateChange: function (e) {
                            syncPlayState(e.data);
                            if (e.data === 0) onTrackEnded();
                            if (e.data === 1 && !playFired) {
                                playFired = true;
                                pvTrackEvent('play', ytId);
                            }
                        }
                    }
                });
            } catch (err) {
                clearTimeout(spinnerTimer);
                hideSpinner();
            }
        });
    }

    function destroyPlayer() {
        stopTracking();
        clearTimeout(spinnerTimer);
        if (ytPlayer) { try { ytPlayer.destroy(); } catch (e) {} ytPlayer = null; }
        if (iframeHolder) iframeHolder.innerHTML = '';
        player.classList.remove('pvm-player--playing');
    }

    /* ── Play state ───────────────────────────────────────────────── */
    function syncPlayState(state) {
        if (state === 1) player.classList.add('pvm-player--playing');
        else if (state === 2 || state === 0) player.classList.remove('pvm-player--playing');
    }

    function togglePlay() {
        if (!ytPlayer) return;
        try {
            if (ytPlayer.getPlayerState() === 1) ytPlayer.pauseVideo();
            else ytPlayer.playVideo();
        } catch (e) {}
    }

    /* ── Analytics bridge — dispatches to pv-tracker.min.js ──────── */
    function pvTrackEvent(event, youtubeId) {
        document.dispatchEvent(new CustomEvent('pv:track-event', {
            detail: { event: event, youtubeId: youtubeId }
        }));
    }

    /* ── Progress tracking + analytics depth milestones ──────────── */
    function startTracking(ytId) {
        stopTracking();
        var depthFired = {};
        progressInterval = setInterval(function () {
            if (!ytPlayer) return;
            try {
                var sec = ytPlayer.getCurrentTime();
                var dur = ytPlayer.getDuration();
                if (dur > 0) {
                    var pct = sec / dur;
                    if (progressFill)     progressFill.style.width     = Math.min(pct * 100, 100).toFixed(1) + '%';
                    if (miniProgressFill) miniProgressFill.style.width = Math.min(pct * 100, 100).toFixed(1) + '%';
                    if (timeCur) timeCur.textContent = formatTime(sec);
                    if (timeDur) timeDur.textContent = formatTime(dur);
                    if (progressBar) progressBar.setAttribute('aria-valuenow', Math.round(pct * 100));
                    var p = pct * 100;
                    if (p >= 25  && !depthFired.d25)  { depthFired.d25  = true; pvTrackEvent('d25',  ytId); }
                    if (p >= 50  && !depthFired.d50)  { depthFired.d50  = true; pvTrackEvent('d50',  ytId); }
                    if (p >= 75  && !depthFired.d75)  { depthFired.d75  = true; pvTrackEvent('d75',  ytId); }
                    if (p >= 100 && !depthFired.d100) { depthFired.d100 = true; pvTrackEvent('d100', ytId); }
                }
            } catch (e) {}
        }, 1000);
    }

    function stopTracking() {
        if (progressInterval) { clearInterval(progressInterval); progressInterval = null; }
    }

    function seekToPct(pct) {
        if (!ytPlayer) return;
        try {
            var dur = ytPlayer.getDuration();
            if (dur > 0) ytPlayer.seekTo(dur * pct, true);
        } catch (e) {}
    }

    /* ── Track ended — respects loop mode ────────────────────────── */
    function onTrackEnded() {
        if (loopMode === 'one') {
            try { ytPlayer.seekTo(0, true); ytPlayer.playVideo(); } catch (e) {}
            return;
        }
        if (current < playlist.length - 1) {
            navigate(1);
        } else if (loopMode === 'all') {
            current = 0;
            loadSlide(0);
            buildQueue();
            if (stageEl && window.matchMedia && window.matchMedia('(min-width: 1024px)').matches) slideStage(1);
        } else {
            player.classList.remove('pvm-player--playing');
        }
    }

    /* ── Navigation ───────────────────────────────────────────────── */
    function navigate(delta) {
        var target = current + delta;
        // Loop-all wraps around at the edges.
        if (target < 0) {
            if (loopMode === 'all') target = playlist.length - 1;
            else return;
        } else if (target >= playlist.length) {
            if (loopMode === 'all') target = 0;
            else return;
        }

        var canSlide = stageEl && window.matchMedia
            && window.matchMedia('(min-width: 1024px)').matches;

        current = target;
        loadSlide(current);
        buildQueue();
        if (canSlide) slideStage(delta);
    }

    function updateNavBtns() {
        var atStart = (current === 0);
        var atEnd   = (current >= playlist.length - 1);
        if (prevBtn)     prevBtn.disabled    = atStart && loopMode !== 'all';
        if (nextBtn)     nextBtn.disabled    = atEnd   && loopMode !== 'all';
        if (miniPrevBtn) miniPrevBtn.disabled = atStart && loopMode !== 'all';
        if (miniNextBtn) miniNextBtn.disabled = atEnd   && loopMode !== 'all';
    }

    /* ── Loop (cycle: none → all → one) ──────────────────────────── */
    function cycleLoop() {
        if      (loopMode === 'none') loopMode = 'all';
        else if (loopMode === 'all')  loopMode = 'one';
        else                          loopMode = 'none';

        if (loopBtn) {
            loopBtn.dataset.loopMode = loopMode;
            loopBtn.setAttribute('aria-pressed', loopMode !== 'none' ? 'true' : 'false');
            var labels = { none: 'Repeat off', all: 'Repeat all', one: 'Repeat one' };
            loopBtn.setAttribute('aria-label', labels[loopMode]);
        }
        if (loopBadge) loopBadge.textContent = loopMode === 'one' ? '1' : '';
        updateNavBtns();
        updateCarousel();
    }

    /* ── Shuffle ──────────────────────────────────────────────────── */
    function toggleShuffle() {
        shuffleActive = !shuffleActive;
        if (shuffleBtn) shuffleBtn.setAttribute('aria-pressed', String(shuffleActive));
        if (shuffleActive) {
            originalPlaylist = playlist.slice();
            var cur = playlist[current];
            for (var i = playlist.length - 1; i > 0; i--) {
                var j = Math.floor(Math.random() * (i + 1));
                var t = playlist[i]; playlist[i] = playlist[j]; playlist[j] = t;
            }
            var ni = playlist.findIndex(function (v) { return v.youtubeId === (cur && cur.youtubeId); });
            if (ni > 0) { var tmp = playlist[0]; playlist[0] = playlist[ni]; playlist[ni] = tmp; }
            current = 0;
        } else {
            var curSlide = playlist[current];
            playlist = originalPlaylist.slice();
            current  = playlist.findIndex(function (v) { return v.youtubeId === (curSlide && curSlide.youtubeId); });
            if (current < 0) current = 0;
        }
        buildQueue();
        updateCarousel();
    }

    /* ── Volume ───────────────────────────────────────────────────── */
    function onVolumeDrag(e) {
        if (!volumeTrack) return;
        var rect = volumeTrack.getBoundingClientRect();
        var pct  = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        setVolume(Math.round(pct * 100));
    }

    function setVolume(vol) {
        currentVolume = Math.max(0, Math.min(100, vol));
        isMuted = false;
        if (ytPlayer) try { ytPlayer.unMute(); ytPlayer.setVolume(currentVolume); } catch (e) {}
        updateVolumeUI();
    }

    function toggleMute() {
        isMuted = !isMuted;
        if (ytPlayer) try {
            if (isMuted) ytPlayer.mute();
            else { ytPlayer.unMute(); ytPlayer.setVolume(currentVolume); }
        } catch (e) {}
        updateVolumeUI();
    }

    function updateVolumeUI() {
        var displayVol = isMuted ? 0 : currentVolume;
        if (volumeFill) volumeFill.style.width = displayVol + '%';
        if (volumeTrack) volumeTrack.setAttribute('aria-valuenow', displayVol);

        var level = isMuted || currentVolume === 0 ? 'mute' : currentVolume < 50 ? 'low' : 'full';
        player.dataset.volLevel = level;
    }

    /* ── Queue list ───────────────────────────────────────────────── */
    function buildQueue() {
        if (!queueList) return;
        queueList.innerHTML = '';
        var queueSection = player ? player.querySelector('.pvm-queue-section') : null;
        var count = 0;

        playlist.forEach(function (slide, i) {
            if (i === current) return; // current track plays above — omit from "Up Next"
            count++;
            var item = document.createElement('div');
            item.className = 'pvm-queue-item';
            item.setAttribute('role', 'listitem');
            var thumbHtml = slide.thumb
                ? '<img class="pvm-queue-item__thumb" src="' + esc(slide.thumb) + '" alt="" loading="lazy">'
                : '<div class="pvm-queue-item__thumb-placeholder"><svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg></div>';
            item.innerHTML =
                '<div class="pvm-queue-item__thumb-wrap">' + thumbHtml + '</div>' +
                '<div class="pvm-queue-item__info">' +
                '<div class="pvm-queue-item__title">' + esc(slide.title) + '</div>' +
                '</div>';
            item.addEventListener('click', (function (idx) {
                return function () { current = idx; loadSlide(current); buildQueue(); };
            }(i)));
            queueList.appendChild(item);
        });

        if (queueSection) queueSection.hidden = (count === 0);
        if (queueCountEl) queueCountEl.textContent = count > 0 ? count + ' track' + (count !== 1 ? 's' : '') : '';
        updateNavBtns();
    }

    /* ── Mini-bar ─────────────────────────────────────────────────── */
    function updateMiniBar() {
        var slide = playlist[current];
        if (!slide) return;
        if (miniTitle)  miniTitle.textContent  = slide.title  || '';
        if (miniThumb) { miniThumb.src = slide.thumb || ''; miniThumb.alt = slide.title || ''; }
    }

    /* ── Entry notification ───────────────────────────────────────── */
    function showEntryNotification() {
        var toast = document.createElement('div');
        toast.className = 'pvm-entry-toast';
        toast.innerHTML =
            '<svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">' +
            '<path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/>' +
            '</svg> Now playing in Music Mode';
        document.body.appendChild(toast);
        requestAnimationFrame(function () {
            requestAnimationFrame(function () { toast.classList.add('pvm-entry-toast--show'); });
        });
        setTimeout(function () {
            toast.classList.remove('pvm-entry-toast--show');
            setTimeout(function () { if (toast.parentNode) toast.parentNode.removeChild(toast); }, 300);
        }, 3000);
    }

    /* ── Spinner ──────────────────────────────────────────────────── */
    function showSpinner() { if (spinner) spinner.removeAttribute('hidden'); }
    function hideSpinner() { if (spinner) spinner.setAttribute('hidden', ''); }

    /* ── Utilities ────────────────────────────────────────────────── */
    function formatTime(sec) {
        sec = Math.floor(sec || 0);
        var m = Math.floor(sec / 60), s = sec % 60;
        return m + ':' + (s < 10 ? '0' : '') + s;
    }

    function esc(str) {
        return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    }

    /* ── Public API ───────────────────────────────────────────────── */
    window.pvMusicPlayer = {
        openFromTrigger: openFromTrigger,
        isActive:        isActive,
        minimize:        minimize,
        restore:         restore,
        close:           forceClose
    };

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
    else init();
}());
